import Foundation

let questions10: [QuizQuestion] = [
QuizQuestion(id:731,question:"O que o livro de Provérbios ensina sobre a língua?",options:["A língua não tem poder","'A morte e a vida estão no poder da língua' (Pv 18:21) — a fala pode edificar ou destruir; o sábio controla suas palavras","A língua é apenas para comunicação","Somente o que se faz importa"],correctIndex:1,explanation:"Provérbios trata extensivamente da língua: Pv 15:4; 18:21; 21:23. A fala revela o coração e tem poder real de vida ou morte.",reference:"Provérbios 18:21",category:.profetas,propheticMeaning:"Tiago 3:6 complementa: 'a língua é um fogo, o mundo da iniquidade.' O mesmo órgão com que 'bendizemos o Senhor' pode 'amaldiçoar' — ambivalência que só o Espírito transforma. Controlar a língua é controlar todo o homem."),
QuizQuestion(id:732,question:"O que Provérbios 16:18 alerta?",options:["A humildade traz queda","'Antes da ruína, o coração do homem se ensoberbece, e antes da queda, a altivez de espírito'","A riqueza precede a queda","O sucesso nunca leva à queda"],correctIndex:1,explanation:"Provérbios 16:18: o orgulho precede a queda — padrão observado na experiência humana e revelado nas histórias de Saul, Nabucodonosor e outros na Bíblia.",reference:"Provérbios 16:18",category:.profetas,propheticMeaning:"Nabucodonosor na loucura (Dn 4) é a ilustração mais dramática: no auge do orgulho ('não é esta a grande Babilônia que eu edifiquei?') foi imediatamente humilhado. A soberba é cega à sua própria vulnerabilidade."),
QuizQuestion(id:733,question:"O que Provérbios 3:5-6 orienta sobre a confiança?",options:["Confie em sua própria sabedoria","'Confia no Senhor de todo o teu coração e não te estribes no teu próprio entendimento. Reconhece-o em todos os teus caminhos, e ele endireitará as tuas veredas'","Confie nos especialistas","Confie na maioria"],correctIndex:1,explanation:"Provérbios 3:5-6 é um dos versículos mais amados da Bíblia: confiança total em Deus (não parcial), rejeição da autossuficiência intelectual, reconhecimento de Deus em tudo.",reference:"Provérbios 3:5-6",category:.profetas,propheticMeaning:"'Reconhece-o em todos os teus caminhos' (bechol derachecha da'ehu) — em cada bifurcação, grande ou pequena, trazer Deus à cena. A sabedoria bíblica não compartimentaliza a vida em sagrado e secular."),
QuizQuestion(id:734,question:"O que o Cântico dos Cânticos celebra?",options:["Apenas a relação de Deus com Israel","O amor conjugal entre um homem e uma mulher — celebrado como dom de Deus; também lido como alegoria do amor de Deus por Israel (judaísmo) ou de Cristo pela Igreja (cristãos)","Apenas alegorias espirituais","A busca da sabedoria"],correctIndex:1,explanation:"Cântico dos Cânticos: poesia de amor que celebra a beleza do amor humano. A tradição cristã viu em Cristo e a Igreja; a judaica em Deus e Israel — ambas as leituras são válidas e complementares.",reference:"Cântico dos Cânticos 8:6-7",category:.profetas,propheticMeaning:"'Forte como a morte é o amor... as grandes águas não podem apagar o amor' (Ct 8:6-7) — a permanência do amor conjugal como imagem do amor de Deus por seu povo, que não pode ser apagado nem pelo julgamento nem pela separação."),
QuizQuestion(id:735,question:"Quem era Ester e o que ela arriscou?",options:["Uma profetisa israelita","Uma órfã judaica que se tornou rainha da Pérsia sob Assuero; arriscou a vida ao se apresentar ao rei sem ser convocada para interceder por seu povo ameaçado de extermínio por Hamã","Uma sacerdotisa de Israel","Uma guerreira judaica"],correctIndex:1,explanation:"Ester 4:16: 'irei ao rei... e se perecer, perecerei' — Mardoqueu a encorajou: 'Quem sabe se para um momento como este tu chegaste ao reino?' (4:14).",reference:"Ester 4:14-16",category:.profetas,propheticMeaning:"'Para um momento como este' — a providência de Deus colocando a pessoa certa no lugar certo na hora certa. Deus não é mencionado no livro de Ester, mas sua mão é visível em cada evento. A providência invisível de Deus."),
QuizQuestion(id:736,question:"O que é a 'lei dos nazireus' em Números 6?",options:["Uma lei sobre impurezas","O voto voluntário de separação especial a Deus: não beber vinho, não cortar o cabelo e não tocar cadáveres — por tempo determinado ou para a vida (Sansão, Samuel, João Batista)","Uma lei apenas para sacerdotes","Uma lei de purificação do templo"],correctIndex:1,explanation:"Números 6:1-21: o nazireu (de nazar — separado, consagrado) fazia voto voluntário de separação intensificada a Deus. Ao completar, oferecia sacrifícios e raspava o cabelo sagrado.",reference:"Números 6:2-8",category:.geral,propheticMeaning:"O voto nazireu representava uma vida totalmente consagrada a Deus — tipo do cristão chamado a ser 'nazireu permanente' (Rm 12:1): separado ao Senhor, vivendo de forma distinta no mundo."),
QuizQuestion(id:737,question:"O que é o 'sacerdócio universal dos crentes'?",options:["Que todos podem ser pastores","A doutrina reformada de 1 Pedro 2:9: 'vós sois... sacerdócio real' — todo crente tem acesso direto a Deus (sem necessidade de intermediário humano) e é chamado a oferecer sacrifícios espirituais","Que não há necessidade de líderes","Que todos celebram a missa"],correctIndex:1,explanation:"1 Pedro 2:9: 'real sacerdócio, nação santa, povo adquirido por Deus' — a Igreja cumprindo o que Israel foi chamado a ser (Êx 19:6). Todo crente é sacerdote.",reference:"1 Pedro 2:9; Êxodo 19:6",category:.geral,propheticMeaning:"O sacerdócio universal não nega a liderança (Ef 4:11) mas afirma que Cristo é o único sumo sacerdote (Hb 7:24-25) e que não há classe sacerdotal intermediária entre o crente e Deus — a lei foi cumprida na Encarnação."),
QuizQuestion(id:738,question:"Qual profecia de Miquéias 5:2 é cumprida no nascimento de Jesus?",options:["'O Messias nascerá em Jerusalém'","'Tu, Belém Efrata... de ti me sairá o que há de reinar em Israel; as suas origens são desde os tempos antigos, desde os dias da eternidade'","'Uma virgem conceberá'","'O Messias virá do Egito'"],correctIndex:1,explanation:"Miquéias 5:2: Belém identificada como lugar de nascimento do Messias — citada pelos sumos sacerdotes e escribas ao Herodes (Mt 2:5-6) quando os magos perguntaram onde nasceria o rei dos judeus.",reference:"Miquéias 5:2; Mateus 2:5-6",category:.profetas,propheticMeaning:"'Suas origens são desde os tempos antigos, desde os dias da eternidade' (Mq 5:2) — o nascido em Belém tem origem eterna. Combina a humanidade (nascido em Belém) com a divindade (existente desde a eternidade)."),
QuizQuestion(id:739,question:"O que é o 'sinal de Jonas' que Jesus mencionou?",options:["A pregação de Jonas apenas","'Assim como Jonas ficou três dias e três noites no ventre do peixe, assim o Filho do Homem ficará três dias e três noites no coração da terra' — a morte e ressurreição como o sinal definitivo","Uma tempestade no mar","O arrependimento de Nínive"],correctIndex:1,explanation:"Mateus 12:39-40: Jesus recusou dar sinais miraculosos aos escribas e fariseus — o único sinal seria o da ressurreição, tipo da experiência de Jonas.",reference:"Mateus 12:39-40",category:.geral,propheticMeaning:"Jonas pregando ressurreição (saiu do ventre do peixe vivo) é o sinal que Jesus aplicou a si mesmo. Se Jonas ressuscitando da 'morte' motivou o arrependimento de Nínive, quanto mais a ressurreição real de Cristo?"),
QuizQuestion(id:740,question:"O que é a 'parusia' (segunda vinda) na esperança cristã?",options:["A presença de Cristo apenas no coração","A vinda visível e gloriosa de Cristo no fim dos tempos (parousia = presença, chegada) — precedida de sinais, súbita como relâmpago, com ressurreição dos mortos e julgamento final","Apenas uma metáfora de renovação","Um evento puramente espiritual sem manifestação física"],correctIndex:1,explanation:"1 Ts 4:16-17; Mt 24:27-31: a parusia será audível (trombeta), visível (relâmpago, nuvens) e universal (toda nação verá). Os mortos ressuscitarão e os vivos serão transformados.",reference:"1 Tessalonicenses 4:16-17",category:.geral,propheticMeaning:"'Todo olho o verá' (Ap 1:7) — a parusia não é privada nem espiritual apenas. Como a ascensão foi física e visível (At 1:9-11), assim será a volta. Os anjos prometeram: 'virá assim como o vistes ir' (At 1:11)."),
QuizQuestion(id:741,question:"O que Paulo ensina sobre a carne e o Espírito em Gálatas 5:16-25?",options:["Que a carne é o corpo físico mau","Carne (sarx) = natureza humana caída oposta a Deus; Espírito (pneuma) = o Espírito Santo e a nova natureza. 'Andai pelo Espírito e não satisfareis os desejos da carne'","Que o físico é inerentemente mau","Que Espírito e carne coexistem em paz"],correctIndex:1,explanation:"Gálatas 5:16-25: o 'fruto do Espírito' (amor, alegria, paz...) em contraste com as 'obras da carne' (imoralidade, idolatria...). O crente crucificou a carne (v.24) e deve andar pelo Espírito.",reference:"Gálatas 5:16-25",category:.geral,propheticMeaning:"'Fruto do Espírito' (singular!) — não frutos mas um fruto com nove aspectos, todos provenientes do Espírito. O crescimento espiritual não é conseguir características individuais mas o desenvolvimento do caráter de Cristo."),
QuizQuestion(id:742,question:"O que é a 'paciência dos santos' em Apocalipse 14:12?",options:["Tolerância religiosa","'Aqui está a paciência dos santos, os que guardam os mandamentos de Deus e a fé em Jesus' — perseverança fiel em tempos de pressão extrema","Passividade diante de injustiças","Uma virtude desnecessária"],correctIndex:1,explanation:"Apocalipse 14:12: 'hypomonē' (perseverança ativa, não passividade) dos santos que mantêm dupla lealdade: mandamentos de Deus e fé em Jesus — em contexto de marcas da besta e perseguição.",reference:"Apocalipse 14:12",category:.geral,propheticMeaning:"A perseverança apocalíptica não é aguardar passivamente mas manter a fidelidade ativa sob pressão máxima — o mesmo princípio de Hebreus 12:1 aplicado ao contexto do Apocalipse onde a apostasia é opção fácil."),
QuizQuestion(id:743,question:"Quem são os 'dois testemunhos' de Apocalipse 11?",options:["Pedro e Paulo","Duas testemunhas com poderes de Moisés (pragas) e Elias (fogo do céu) que profetizam 1.260 dias, são mortas, ressuscitam após 3,5 dias e sobem ao céu — a identidade é debatida: Moisés e Elias ou tipos de toda a Igreja testemunha","João e Tiago","Enoque e Noé"],correctIndex:1,explanation:"Apocalipse 11:3-12: os dois testemunhos têm poderes de Moisés (transformar água em sangue) e Elias (fechar o céu) — tipicamente identificados como Moisés e Elias ou como símbolo da Igreja profética.",reference:"Apocalipse 11:3-12",category:.geral,propheticMeaning:"Dois testemunhos (número legal de confirmação em Dt 19:15) profetizando com poder mosaico-elíaco é a Igreja cumprindo o ministério profético integrado dos dois testamentos — Lei e Profetas encarnados na comunidade cristã."),
QuizQuestion(id:744,question:"O que é o 'templo de Deus' em 2 Tessalonicenses 2:4?",options:["O templo de Salomão","O lugar onde o 'homem da iniquidade' se assentará, 'anunciando-se a si mesmo como Deus' — alusão ao templo de Jerusalém ou ao templo simbólico da comunidade de Deus","O Vaticano","Uma referência ao coração humano apenas"],correctIndex:1,explanation:"2 Ts 2:3-4: o 'homem da iniquidade' (filho da perdição) que se opõe a tudo chamado Deus e 'se assentar no templo de Deus' — linguagem que ecoa Daniel 11:36 e Mt 24:15.",reference:"2 Tessalonicenses 2:3-4",category:.geral,propheticMeaning:"A profanação do templo como sinal escatológico (2 Ts 2:4) repete o padrão de Antíoco IV, Calígula e a destruição de 70 d.C. — o antijristo final é revelado pela usurpação da adoração que pertence a Deus."),
QuizQuestion(id:745,question:"O que Jesus disse sobre a 'luz do mundo' em João 8:12?",options:["A Igreja é a luz do mundo apenas","'Eu sou a luz do mundo; quem me segue não andará em trevas, mas terá a luz da vida'","Os judeus são a luz do mundo","A lei é a luz do mundo"],correctIndex:1,explanation:"João 8:12: o segundo 'Eu sou' em João — Jesus como 'luz do mundo' em contraste com as trevas do pecado e da morte espiritual.",reference:"João 8:12",category:.jesus,propheticMeaning:"Jesus como 'luz do mundo' no contexto da festa dos Tabernáculos (onde grandes candelabros iluminavam Jerusalém) proclamou que era a realidade que o rito simbolizava. A luz que ilumina cada homem que vem ao mundo (Jo 1:9)."),
QuizQuestion(id:746,question:"O que Jesus ensinou sobre a humildade do servo em Marcos 10:43-45?",options:["O maior deve dominar os outros","'Entre vós, qualquer que quiser ser grande será vosso servo... pois o Filho do Homem não veio para ser servido, mas para servir e dar a sua vida em resgate de muitos'","A hierarquia é o modelo do reino","A ambição é virtude"],correctIndex:1,explanation:"Marcos 10:43-45: a grande inversão do reino — grandeza por serviço, não por domínio. Jesus como o modelo: veio para servir e dar sua vida.",reference:"Marcos 10:43-45",category:.geral,propheticMeaning:"'Dar a sua vida em resgate (lytron) de muitos' é uma das declarações mais claras de Jesus sobre a natureza expiatória de sua morte — o preço pago para libertar os cativos, o Servo Sofredor de Isaías 53 em ação."),
QuizQuestion(id:747,question:"O que é a parábola do samaritano compassivo (Lucas 10:25-37)?",options:["Uma história sobre samaritanos","Um especialista da lei perguntou 'quem é o meu próximo?' — Jesus respondeu com a parábola: um homem ferido ignorado por sacerdote e levita, socorrido por um samaritano desprezado. Próximo é quem age com misericórdia","Uma parábola sobre viagens","Uma história sobre a lei de Moisés"],correctIndex:1,explanation:"Lucas 10:25-37: Jesus redefiniu 'próximo' — não quem merece nosso amor mas quem pratica amor. O samaritano desprezado como modelo de amor ao próximo para um especialista da lei judaica.",reference:"Lucas 10:25-37",category:.geral,propheticMeaning:"O samaritano 'desprezado' sendo o herói reverte a expectativa — a graça vem de onde não é esperada. Jesus como o verdadeiro Samaritano: o desprezado que passa pelo homem ferido (a humanidade caída) e paga o preço da cura."),
QuizQuestion(id:748,question:"O que Jesus disse sobre o amor aos inimigos em Mateus 5:44?",options:["Amar apenas quem te ama","'Amai os vossos inimigos e orai pelos que vos perseguem, para que sejais filhos do vosso Pai celestial, que faz nascer o seu sol sobre maus e bons'","Tolere os inimigos","Ignore seus inimigos"],correctIndex:1,explanation:"Mateus 5:44-45: o amor aos inimigos distingue o discípulo do comum — os publicanos amam os que os amam (v.46). O amor cristão imita Deus que faz chover sobre justos e injustos.",reference:"Mateus 5:44-45",category:.geral,propheticMeaning:"Amar o inimigo é o mais radical mandamento do reino — impossível pela natureza humana caída, possível apenas pelo Espírito que derrama o amor de Deus (Rm 5:5). É a expressão mais clara da diferença entre o reino de Cristo e o mundo."),
QuizQuestion(id:749,question:"O que Jesus ensinou sobre não acumular riquezas em Mateus 6:19-21?",options:["Acumule riquezas para a família","'Não ajunteis tesouros na terra... Mas ajuntai tesouros no céu... porque onde estiver o teu tesouro, aí estará também o teu coração'","As riquezas são neutrales","Apenas as riquezas mal-obtidas são proibidas"],correctIndex:1,explanation:"Mateus 6:19-21: Jesus contrasta dois tipos de acumulação — terrena (corruptível, roubável) vs. celestial (permanente). A questão não é apenas onde guardamos dinheiro mas onde está nosso coração.",reference:"Mateus 6:19-21",category:.geral,propheticMeaning:"'Onde o tesouro, aí o coração' — a direção do desejo determina a identidade. Paulo: 'pondes a mente nas coisas lá do alto, não nas da terra' (Cl 3:2). A reorientação escatológica afeta o gerenciamento material presente."),
QuizQuestion(id:750,question:"O que Jesus disse sobre o 'ojo simples' em Mateus 6:22-23?",options:["Sobre cuidado físico dos olhos","'O olho é a lâmpada do corpo; assim, se o teu olho for são (haplous — generoso/simples/focado), todo o teu corpo será cheio de luz' — a visão espiritual focada em Deus ilumina toda a vida","Sobre o evitar leitura em excesso","Sobre a cegueira física"],correctIndex:1,explanation:"Mateus 6:22-23: 'haplous' significa tanto 'simples/íntegro' quanto 'generoso' (uso semítico). O olho focado em Deus (e não dividido entre Deus e o dinheiro — v.24) ilumina a vida inteira.",reference:"Mateus 6:22-23",category:.geral,propheticMeaning:"O 'olho mau' (ponēros — maligno/avarento) vs 'olho são' (haplous — íntegro/generoso) situa a questão do tesouro (v.19-21) na orientação do desejo — a avareza é cegueira espiritual que transforma toda a vida em trevas."),
QuizQuestion(id:751,question:"Qual foi a traição de Judas Iscariotes e seu desfecho?",options:["Judas traiu e foi perdoado","Judas combinou com os sumos sacerdotes entregar Jesus por 30 moedas de prata, o identificou no Getsêmani com um beijo, e depois, cheio de remorso, devolveu o dinheiro e se enforcou","Judas negou conhecer Jesus","Judas abandonou Jesus mas não o entregou"],correctIndex:1,explanation:"Mateus 26:14-16; 27:3-10: Judas entregou Jesus por 30 moedas de prata (cumprindo Zacarias 11:12-13) e ao ver Jesus condenado, teve remorso e se enforcou.",reference:"Mateus 26:14-16; Zacarias 11:12-13",category:.geral,propheticMeaning:"As 30 moedas de prata (preço de um escravo, Êx 21:32) e seu destino (campo do oleiro — Zc 11:13) foram profetizados por Zacarias 500 anos antes. A traição não surpreendeu a Deus; foi incorporada ao plano redentor."),
QuizQuestion(id:752,question:"O que foi o julgamento de Jesus diante de Pôncio Pilatos?",options:["Um julgamento justo","Pilatos três vezes declarou Jesus inocente ('Não acho nenhum crime neste homem') mas cedeu à pressão da multidão e o entregou para crucificação — lavando as mãos mas assumindo a responsabilidade","Um tribunal sem resultado","Um tribunal apenas religioso"],correctIndex:1,explanation:"Lucas 23:4,14,22; João 19:4-6: Pilatos declarou três vezes a inocência de Jesus mas capitulou à pressão. A lavagem das mãos (Mt 27:24) não eliminou a responsabilidade.",reference:"Lucas 23:14-16; João 19:4-6",category:.geral,propheticMeaning:"A inocência declarada três vezes pelo juiz romano é paradoxalmente testemunho da culpabilidade da condenação — o sistema judicial romano, que os judeus usaram para eliminar Jesus, proclamou sua inocência. A injustiça da cruz foi legal e testemunhada."),
QuizQuestion(id:753,question:"O que foi a morte de Jesus na Cruz e seus últimos momentos?",options:["Jesus morreu sem dizer nada","Jesus fez sete declarações na cruz; na crucificação houve três horas de trevas ao meio-dia; ao morrer, o véu do templo rasgou-se de cima abaixo, houve terremo e ressuscitaram santos","Jesus morreu rapidamente","Apenas João testemunhou a morte"],correctIndex:1,explanation:"Mateus 27:45-56; Lucas 23:34-46; João 19:26-30: as circunstâncias sobrenaturais da morte — trevas (Ex 10), véu rasgado, terremoto — confirmam o significado cósmico do evento.",reference:"Mateus 27:45-54",category:.geral,propheticMeaning:"O véu do templo rasgando-se 'de cima abaixo' (por Deus, não por humanos) sinalizou o fim da separação entre Deus e o homem — o Santo dos Santos agora acessível a todos. Hebreus 10:19-20: 'novo e vivo caminho.'"),
QuizQuestion(id:754,question:"O que foi a ressurreição de Jesus e suas primeiras aparições?",options:["A ressurreição foi apenas espiritual","A sepultura vazia foi descoberta pelas mulheres na manhã do primeiro dia da semana; Jesus apareceu: a Maria Madalena, às mulheres, a Pedro, aos discípulos de Emaús, aos onze, e a mais de 500 de uma vez","Apenas os apóstolos viram Jesus ressurreto","A ressurreição ocorreu no sábado"],correctIndex:1,explanation:"1 Co 15:3-8: Paulo lista as aparições do ressurreto. João 20: Maria Madalena foi a primeira testemunha. Lucas 24:13-35: os discípulos de Emaús.",reference:"1 Coríntios 15:3-8",category:.geral,propheticMeaning:"'Apareceu a mais de quinhentos irmãos de uma vez, dos quais a maior parte ainda vive' (1 Co 15:6) — Paulo escrevendo ~25 anos depois convidando o leitor a checar com as testemunhas vivas. Não é mito; é testável."),
QuizQuestion(id:755,question:"O que é a 'ascensão de Jesus' em Atos 1?",options:["Que Jesus subiu ao céu em visão","Jesus foi levado visível para o alto enquanto os discípulos olhavam, uma nuvem o encobriu, e dois anjos anunciaram que voltaria 'da mesma forma' — Jesus reinando à direita do Pai","Uma parábola sobre a glória de Cristo","Um evento apenas simbólico"],correctIndex:1,explanation:"Atos 1:9-11: a ascensão foi física e visível — testemunhada pelos discípulos. Inaugurou o reinado celestial de Cristo (Ef 1:20-21) e a era do Espírito.",reference:"Atos 1:9-11; Efésios 1:20-21",category:.geral,propheticMeaning:"A ascensão é a glorificação do Filho do Homem ao trono que Daniel 7:13-14 profetizou — 'vindo às nuvens ao Ancião de Dias e recebendo domínio.' Não é separação mas entronização que permite a presença universal pelo Espírito."),
QuizQuestion(id:756,question:"O que Paulo ensina sobre a glorificação em Romanos 8:30?",options:["Glorificação é apenas futura e incerta","'A quem predestinou, a esses também chamou; e a quem chamou, a esses também justificou; e a quem justificou, a esses também glorificou' — o passado no grego garante a certeza do futuro","Glorificação depende do crente","Apenas alguns crentes serão glorificados"],correctIndex:1,explanation:"Romanos 8:30: a 'cadeia de ouro' — predestinação→chamado→justificação→glorificação — Paulo usa o aoristo (passado) para a glorificação, indicando sua certeza absoluta.",reference:"Romanos 8:30",category:.geral,propheticMeaning:"O aoristo 'glorificou' (passado!) aplicado ao futuro confirma que a glorificação é tão certa quanto o passado — do ponto de vista de Deus eterno, todos os seus já estão glorificados. A segurança da salvação fundamentada na perspectiva divina."),
QuizQuestion(id:757,question:"O que Hebreus 1 declara sobre a superioridade de Cristo?",options:["Cristo é semelhante aos anjos","'Deus, tendo antigamente falado pelos profetas... nestes últimos dias nos falou pelo Filho, a quem constituiu herdeiro de todas as coisas' — Cristo como revelação definitiva superior aos profetas, anjos e Moisés","Cristo é um anjo superior","Cristo apenas completou a lei"],correctIndex:1,explanation:"Hebreus 1:1-4: a superioridade de Cristo como revelação definitiva de Deus — ele é 'resplendor da glória e imagem do ser de Deus' e se assentou 'à direita da Majestade nas alturas.'",reference:"Hebreus 1:1-4",category:.geral,propheticMeaning:"'Nestes últimos dias nos falou pelo Filho' — a revelação progressiva de Deus culmina e é substituída por revelação pessoal encarnada. Não mais através de intermediários (profetas, anjos) mas pelo próprio Filho que 'é a imagem do Deus invisível' (Cl 1:15)."),
QuizQuestion(id:758,question:"O que Paulo diz sobre a expiação em Romanos 3:25-26?",options:["Que Deus ignorou os pecados no AT","Cristo como 'propiciação' — Deus o propôs publicamente pelo sangue para demonstrar sua justiça; ele passou por alto os pecados anteriores e agora demonstra que é justo E justificador do que crê em Jesus","Que os pecados do AT não eram sérios","Que a expiação é apenas para judeus"],correctIndex:1,explanation:"Rm 3:25-26: o 'propiciador' no AT era o propiciatório (tampa da arca) — Cristo tornou-se o propiciador definitivo, resolvendo o 'problema teológico' de como Deus pôde 'ignorar' pecados anteriores à cruz.",reference:"Romanos 3:25-26",category:.geral,propheticMeaning:"'Para demonstrar a sua justiça' — a cruz não é apenas expressão do amor de Deus mas de sua justiça. O amor sem justiça seria impunidade; a justiça sem amor seria condenação. Na cruz, 'misericórdia e verdade se encontraram; justiça e paz se beijaram' (Sl 85:10)."),
QuizQuestion(id:759,question:"O que Paulo ensina sobre a ceia do Senhor em 1 Coríntios 11:23-26?",options:["A ceia é apenas memória","Jesus instituiu a ceia na noite em que foi traído: pão ('meu corpo') e cálice ('esta taça é o novo pacto no meu sangue') — 'fazei isso em memória de mim... anunciais a morte do Senhor até que ele venha'","A ceia não tem significado real","A ceia transforma literalmente em carne e sangue"],correctIndex:1,explanation:"1 Co 11:23-26: Paulo transmite a tradição da Ceia do Senhor recebida de Cristo — três dimensões: memória (passado), proclamação (presente) e esperança (futuro — 'até que ele venha').",reference:"1 Coríntios 11:23-26",category:.geral,propheticMeaning:"'Anunciais a morte do Senhor até que ele venha' — a Ceia é proclamação evangelística e esperança escatológica simultaneamente. Cada celebração é um sermão sem palavras sobre o passado redentor e o futuro glorioso."),
QuizQuestion(id:760,question:"O que Paulo ensina sobre crescer em Cristo em Efésios 4:15-16?",options:["O crescimento é individual apenas","'Fazendo a verdade em amor, cresceremos em tudo naquele que é a cabeça, Cristo, do qual todo o corpo... resulta no crescimento do corpo para a sua edificação em amor'","Crescimento espiritual é apenas conhecimento","Apenas pastores crescem"],correctIndex:1,explanation:"Ef 4:15-16: o crescimento é a Igreja inteira crescendo em Cristo — 'falando a verdade em amor' e cada membro em sua função. Coletivo e orgânico, não apenas individual.",reference:"Efésios 4:15-16",category:.geral,propheticMeaning:"O corpo crescendo 'de cada junta' (Ef 4:16) revela que a formação espiritual não é isolada — cada membro contribui para e recebe do todo. A solução para a imaturidade espiritual é a comunidade funcionando corretamente."),
QuizQuestion(id:761,question:"O que é o 'dom de profecia' segundo 1 Coríntios 14?",options:["Predição do futuro apenas","Proclamação inspirada pelo Espírito que edifica a Igreja através de edificação, exortação e consolação (v.3) — Paulo o valoriza acima das línguas não interpretadas","Falar em línguas","Ensino de doutrina apenas"],correctIndex:1,explanation:"1 Co 14:1-5: Paulo valoriza a profecia sobre as línguas porque edifica a Igreja. O profeta não está acima do julgamento da comunidade (v.29-32).",reference:"1 Coríntios 14:3",category:.geral,propheticMeaning:"A profecia que edifica, exorta e consola a Igreja é uma das formas do Espírito cuidar de sua comunidade — pastoreio espiritual corporativo. O critério não é o sobrenatural do ato mas o edificante do resultado."),
QuizQuestion(id:762,question:"O que Tiago ensina sobre a prova da fé em Tiago 1:2-4?",options:["Evite todo sofrimento","'Considerai mui grande alegria, meus irmãos, quando passardes por várias provações; sabendo que a prova da vossa fé produz paciência... a fim de que sejais perfeitos e completos'","As provações são punições","Provações são sempre desnecessárias para o crente"],correctIndex:1,explanation:"Tiago 1:2-4: a perspectiva do apóstolo sobre o sofrimento — provações testando a fé produzem perseverança que leva à maturidade. A resposta correta é alegria, não amargura.",reference:"Tiago 1:2-4",category:.geral,propheticMeaning:"'Perfeitos e completos, em nada deficientes' (Tg 1:4) — a meta das provações é a teleiotēs (completude, maturidade). Paulo em Rm 5:3-5 é paralelo: tribulação→perseverança→caráter→esperança. Ambos veem o sofrimento como formativo."),
QuizQuestion(id:763,question:"O que Tiago ensina sobre sabedoria em Tiago 1:5?",options:["Busque sabedoria nos livros","'Se algum de vós tem falta de sabedoria, peça-a a Deus, que a todos dá liberalmente e nada lhes impropera, e ser-lhe-á dada'","A sabedoria vem apenas da experiência","Apenas os maduros recebem sabedoria"],correctIndex:1,explanation:"Tiago 1:5: a sabedoria para enfrentar provações é obtida pela oração — Deus dá liberalmente, sem repreender os que pedem. Contexto imediato: como responder às provações da vida.",reference:"Tiago 1:5",category:.geral,propheticMeaning:"'Sem lhes fazer reprovações' — Deus não envergonha o que pede sabedoria, não importa quantas vezes, não importa quão elementar a pergunta. A generosidade divina em dar sabedoria reflete a generosidade em dar graça."),
QuizQuestion(id:764,question:"O que Pedro ensina sobre o sofrimento justo em 1 Pedro 2:21?",options:["O justo nunca deve sofrer","'Para isso mesmo fostes chamados, porque também Cristo sofreu por vós, deixando-vos exemplo para seguirdes os seus passos' — o sofrimento como participação no padrão de Cristo","O sofrimento é sempre injusto","Somente líderes chamados a sofrer"],correctIndex:1,explanation:"1 Pedro 2:21-24: o Servo Sofredor de Isaías 53 é o modelo — Jesus que 'quando ultrajado não tornava a ultrajar' e 'quando sofria não ameaçava' é o exemplo do crente que sofre injustamente.",reference:"1 Pedro 2:21-24",category:.geral,propheticMeaning:"'Chamados para isso' — o sofrimento justo não é acidente no plano de Deus mas vocação cristã. Não toda forma de sofrimento, mas o sofrimento por fazer o bem (1 Pe 2:20) é participação no padrão do Senhor."),
QuizQuestion(id:765,question:"O que João ensina sobre o teste dos espíritos em 1 João 4:1-3?",options:["Aceite toda revelação como de Deus","'Não creiais em todo espírito, mas provai os espíritos se são de Deus... Todo espírito que confessa que Jesus Cristo veio em carne é de Deus; e todo espírito que não confessa a Jesus não é de Deus'","Evite avaliar profecias","Todos os espíritos são bons"],correctIndex:1,explanation:"1 João 4:1-3: o critério de discernimento — a confissão da encarnação de Cristo. O espírito que nega que Jesus veio em carne (docetismo) não é de Deus.",reference:"1 João 4:1-3",category:.geral,propheticMeaning:"O teste cristológico de 1 João 4 é atemporal — qualquer ensino que diminui a plena humanidade ou plena divindade de Cristo é de outro espírito. A encarnação ('veio em carne') é o eixo da cristologia bíblica."),
QuizQuestion(id:766,question:"O que João diz sobre o amor perfeito em 1 João 4:18?",options:["O amor perfeito é impossível","'No amor não há medo, antes o perfeito amor lança fora o medo, porque o medo tem a ver com o castigo; e quem teme não é perfeito no amor'","O amor perfeito é apenas para Deus","O medo é necessário para o amor"],correctIndex:1,explanation:"1 João 4:18: o amor maduro expulsa o medo (de julgamento, de rejeição). Onde há medo de punição como motivação primária, o amor de Deus ainda não chegou à sua plenitude.",reference:"1 João 4:18",category:.geral,propheticMeaning:"O medo que o amor perfeito expulsa não é o saudável temor reverencial mas o medo servil de punição — a mentalidade de escravo, não de filho. 'Não recebestes o espírito de escravidão para o temor, mas de adoção' (Rm 8:15)."),
QuizQuestion(id:767,question:"O que Judas alerta sobre o perigo do libertinismo em Judas 4?",options:["Não há perigos espirituais reais","Judas alerta contra pessoas que 'mudaram a graça de Deus em libertinagem' — usando a graça como licença para o pecado ('já que sou salvo, posso pecar à vontade')","A graça sempre leva à libertinagem","A libertinagem é aceitável para os maduros"],correctIndex:1,explanation:"Judas 4: a distorção da graça como licença para o pecado é uma das heresias mais antigas e persistentes. Paulo responde em Rm 6:1-2: 'Nós que morremos ao pecado, como viveremos ainda nele?'",reference:"Judas 4; Romanos 6:1-2",category:.geral,propheticMeaning:"'Mudar a graça em libertinagem' perverte tanto a graça (que não é permissão para pecar mas poder para não pecar) quanto a liberdade cristã (que é liberdade do pecado, não para o pecado — Gl 5:13)."),
QuizQuestion(id:768,question:"O que Paulo ensina sobre a 'armadilha da comparação' em 2 Coríntios 10:12?",options:["Comparar-se com outros é neutro","'Os que se medem consigo mesmos e se comparam consigo mesmos não são sábios' — o padrão do cristão é Cristo e a missão dada por Deus, não comparação com outros","Comparação motiva o crescimento","Os melhores cristãos sempre se comparam"],correctIndex:1,explanation:"2 Co 10:12: Paulo critica os que 'se elogiam a si mesmos' comparando-se com outros — a medida correta é o cânone que Deus mesmo estabeleceu (v.13), não o comparativismo humano.",reference:"2 Coríntios 10:12-13",category:.geral,propheticMeaning:"A comparação produz orgulho (me comparo com inferiores) ou inveja (me comparo com superiores) — ambos distorções. O padrão cristão é imitar a Cristo (1 Co 11:1) e correr a própria carreira dada por Deus (Hb 12:1)."),
QuizQuestion(id:769,question:"O que Paulo diz sobre a influência de más companhias em 1 Coríntios 15:33?",options:["As companhias não influenciam a fé","'As más companhias corrompem os bons costumes' — Paulo citando provérbio grego (Menandro) para alertar contra a influência de quem nega a ressurreição","Apenas as companhias ruins no mundo","O crente é imune à influência das companhias"],correctIndex:1,explanation:"1 Co 15:33: no contexto de quem nega a ressurreição, Paulo usa a citação 'phtheirousin ēthē chrēsta homiliai kakai' — os que convivem com os que negam a ressurreição são arrastados.",reference:"1 Coríntios 15:33",category:.geral,propheticMeaning:"A advertência das companhias no contexto da ressurreição mostra que falsas doutrinas se espalham por relacionamentos tanto quanto por argumentos. A comunidade saudável é proteção contra a heresia."),
QuizQuestion(id:770,question:"O que é a 'Grande Babilônia' em Apocalipse 17?",options:["A cidade literal de Babilônia reconstruída","Símbolo de Roma (identificada na época como 'a cidade sobre sete montes') e, por extensão, de todo sistema humano contrário a Deus — econômico, religioso e político que persegue os santos","Um país específico do fim dos tempos","Uma heresia específica"],correctIndex:1,explanation:"Apocalipse 17: a mulher bêbada do sangue dos santos sentada sobre a besta é 'a grande cidade que reina sobre os reis da terra' (v.18) — identificação contemporânea: Roma imperial.",reference:"Apocalipse 17:5,18",category:.geral,propheticMeaning:"'Babilônia' como categoria profética transcende Roma — é todo sistema que substitui Deus pelo dinheiro, poder e prazer. Sua queda (Ap 18) é inevitável porque Deus é o Senhor da história."),
QuizQuestion(id:771,question:"O que Paulo ensina sobre o 'mistério' em Efésios 3:3-6?",options:["Um segredo nunca revelado","'O mistério de Cristo que em outras gerações não foi manifestado aos homens... os gentios são co-herdeiros, co-participantes e co-membros do mesmo corpo'","A salvação dos judeus apenas","A segunda vinda secreta"],correctIndex:1,explanation:"Efésios 3:3-6: 'mystērion' — não segredo absoluto mas revelação do que antes estava velado: os gentios como co-herdeiros na mesma promessa em Cristo. O que o AT anunciava parcialmente foi revelado na Igreja.",reference:"Efésios 3:3-6",category:.geral,propheticMeaning:"O 'mistério' da unidade judeus-gentios em Cristo é uma das revelações mais revolucionárias do NT — o muro que separava (Ef 2:14) foi derrubado. A Igreja multirracial e multinacional é o cumprimento da promessa abraâmica."),
QuizQuestion(id:772,question:"Que é o 'temor do Senhor' nos Salmos e em Provérbios?",options:["Pavor terrorista de Deus","Reverência amorosa, adoração e respeito pelo caráter e poder de Deus — 'o princípio da sabedoria é o temor do Senhor' (Pv 9:10; Sl 111:10); oposto a insolência e autonomia","Medo de ser punido sempre","Uma virtude apenas para não-cristãos"],correctIndex:1,explanation:"Yir'at YHWH (temor do Senhor) é uma postura fundamental: reconhecimento de quem Deus é que orienta todo pensamento e ação. É o início (reshit) da sabedoria, não etapa superada.",reference:"Provérbios 9:10; Salmos 111:10",category:.geral,propheticMeaning:"Em Cristo, o temor do Senhor é transformado — não mais medo servil (escravidão) mas reverência filial: o filho que respeita e ama o Pai porque conhece seu caráter. 'Perfeito amor lança fora o medo' (1 Jo 4:18) é sobre punição, não reverência."),
QuizQuestion(id:773,question:"O que é 'santidade' segundo 1 Pedro 1:15-16?",options:["Perfeição moral humana","'Sede santos em toda a vossa maneira de viver, porque está escrito: Sede santos, porque eu sou santo' — separação ao caráter de Deus em toda a vida, não apenas atos religiosos","Guardar os rituais apenas","Separar-se do mundo completamente"],correctIndex:1,explanation:"1 Pedro 1:15-16 (citando Lv 19:2): santidade como conformidade ao caráter de Deus em 'toda a maneira de viver' — não apenas nos momentos 'sagrados' mas na vida inteira.",reference:"1 Pedro 1:15-16",category:.geral,propheticMeaning:"'Toda a vossa maneira de viver' (anastrophē — comportamento, modo de vida) — a santidade permeia o cotidiano: como tratamos o vizinho, usamos o tempo, gasamos o dinheiro, falamos em private. Não é apenas adoração formal."),
QuizQuestion(id:774,question:"O que João 1:1-3 declara sobre o Logos (Palavra)?",options:["O Logos é uma criatura divina","'No princípio era o Verbo, e o Verbo estava com Deus, e o Verbo era Deus. Todas as coisas foram feitas por ele, e sem ele nada do que foi feito se fez'","O Logos foi criado antes da criação","O Logos é apenas uma força divina"],correctIndex:1,explanation:"João 1:1-3: o Logos preexistente (era — imperfeito de ser, existência contínua no passado), distinto de Deus (com Deus) e idêntico a Deus (era Deus) — a preexistência divina de Cristo.",reference:"João 1:1-3",category:.geral,propheticMeaning:"'No princípio era o Verbo' ecoa Gênesis 1:1 ('no princípio criou Deus') — João identifica o Logos com o agente criador divino. O Verbo que 'se fez carne' (v.14) é o mesmo que existia antes de toda criação."),
QuizQuestion(id:775,question:"O que é a 'encarnação' segundo João 1:14?",options:["Deus aparecendo como visão","'O Verbo se fez carne e habitou entre nós, cheio de graça e de verdade; e vimos a sua glória, glória como do unigênito do Pai'","Uma aparição temporária de Deus","Deus fingindo ser humano"],correctIndex:1,explanation:"João 1:14: 'eskēnōsen' — 'armou sua tenda' entre nós (como o tabernáculo no deserto). A glória que habitou no tabernáculo habitou em carne humana.",reference:"João 1:14",category:.geral,propheticMeaning:"'Armou sua tenda' (eskēnōsen — de skēnē, tenda/tabernáculo) revela que a encarnação é o cumprimento do tabernáculo: a glória shekinah que habitou no tabernáculo agora habita em carne. 'O templo do seu corpo' (Jo 2:21)."),
QuizQuestion(id:776,question:"O que Paulo declara sobre a kenose em Filipenses 2:6-8?",options:["Cristo deixou de ser Deus ao encarnar","'Sendo em forma de Deus, não julgou como usurpação igualar-se com Deus, mas esvaziou-se a si mesmo, tomando a forma de servo... e humilhou-se, tornando-se obediente até à morte de cruz'","Cristo era apenas aparentemente divino","Cristo precisou aprender a ser obediente"],correctIndex:1,explanation:"Fp 2:6-8: a kenose (kenōsis — esvaziamento) de Cristo — ele não abriu mão de atributos divinos mas da expressão da glória divina, tomando forma de servo. O esvaziamento foi de prerrogativas, não de natureza.",reference:"Filipenses 2:6-8",category:.geral,propheticMeaning:"O esvaziamento de Cristo segue o padrão paradoxal do reino: descendo para subir, morrendo para viver, servindo para reinar. A exaltação (Fp 2:9-11) é resposta de Deus à humilhação voluntária — o padrão que o crente deve imitar."),
QuizQuestion(id:777,question:"O que significa Jesus ser 'Alfa e Ômega' em Apocalipse 1:8?",options:["Jesus é inteligente","'Eu sou o Alfa e o Ômega, o princípio e o fim, diz o Senhor Deus, que é, que era e que há de vir, o Todo-Poderoso' — a totalidade da existência encarnada em Cristo","Jesus é eterno mas finito","Cristo é o começo mas não o fim"],correctIndex:1,explanation:"Apocalipse 1:8: a primeira e última letra do alfabeto grego — a totalidade de tudo. Cristo é o começo e o fim, o Todo-Poderoso, o eterno 'Eu sou.'",reference:"Apocalipse 1:8; 22:13",category:.geral,propheticMeaning:"'Que é, era e há de vir' aplica a Jesus a fórmula do YHWH (Êx 3:14) — João identificando inequivocamente Cristo com o Deus do AT. O 'Eu sou' de Êxodo é o 'Eu sou' de João 8:58 e de Apocalipse 1:8."),
QuizQuestion(id:778,question:"O que Jesus disse sobre o nascimento virginal em Lucas 1?",options:["Jesus nunca explicou seu nascimento","O anjo Gabriel anunciou a Maria: 'Conceberás... e darás à luz um filho e chamarás seu nome Jesus.' Maria perguntou 'como será isso?' O anjo respondeu: 'O Espírito Santo virá sobre ti'","O nascimento virginal não está em Lucas","Maria não foi informada antes"],correctIndex:1,explanation:"Lucas 1:26-38: o anúncio a Maria (Anunciação) — concepção pelo Espírito Santo sem intervenção humana. Maria respondeu: 'Eis aqui a serva do Senhor; seja feito segundo a tua palavra.'",reference:"Lucas 1:30-35",category:.geral,propheticMeaning:"Maria como a 'serva do Senhor' (Lc 1:38) é o modelo de fé obediente — receptora ativa da graça soberana de Deus. Sua resposta ('seja feito') contrasta com a incredulidade de Zacarias. A fé que aceita o impossível."),
QuizQuestion(id:779,question:"O que Paulo ensina sobre a 'lei do Cristo' em Gálatas 6:2?",options:["Que a lei de Moisés continua","'Levai os fardos uns dos outros, e assim cumprireis a lei de Cristo' — a lei do amor mútuo que Jesus ensinou é o cumprimento de toda a lei","Que não há lei no NT","Que a lei de Cristo é um conjunto de regras"],correctIndex:1,explanation:"Gl 6:2: 'a lei de Cristo' = o mandamento do amor mútuo (Jo 13:34; 15:12) que Paulo chama de 'lei' porque governa a vida cristã, não por coerção mas por amor.",reference:"Gálatas 6:2; João 13:34",category:.geral,propheticMeaning:"'Carregar os fardos uns dos outros' é o cumprimento prático da lei de Cristo — a comunidade cristã como ambiente de mútua sustentação, em contraste com o individualismo e o 'cada um por si.'"),
QuizQuestion(id:780,question:"O que é a 'graça operante e cooperante' segundo Agostinho e Paulo?",options:["Que a graça é apenas recompensa","Graça operante (Deus age sozinho na regeneração) e cooperante (Deus e o crente agem juntos na santificação) — Fp 2:12-13: 'operai a vossa salvação... pois Deus é o que opera em vós'","Que a graça não existe na santificação","Que o esforço humano é desnecessário"],correctIndex:1,explanation:"Filipenses 2:12-13: o paradoxo da santificação — 'operai vós' (responsabilidade humana) 'pois é Deus que opera' (soberania divina). Não contradição mas dois aspectos da mesma realidade.",reference:"Filipenses 2:12-13",category:.geral,propheticMeaning:"'Deus que opera em vós tanto o querer quanto o fazer' — até o desejo de obedecer é de Deus. A graça não apenas habilita; ela origina. O crente coopera genuinamente com uma operação que Deus inicia e sustenta."),
QuizQuestion(id:781,question:"Qual é o papel do Espírito Santo na regeneração segundo João 3:5-8?",options:["A regeneração é obra apenas humana","'Aquele que não nascer da água e do Espírito não pode entrar no reino de Deus... O vento sopra onde quer... assim é todo aquele que é nascido do Espírito' — o Espírito regenera soberanamente","O Espírito regenera apenas na morte","A regeneração é gradual"],correctIndex:1,explanation:"João 3:5-8: a regeneração pelo Espírito é comparada ao vento — imprevisível em sua origem mas real em seu efeito. O Espírito sopra soberanamente (onde quer), e o nascido do Espírito manifesta vida nova.",reference:"João 3:5-8",category:.geral,propheticMeaning:"'Nascido do Espírito' é passiva — o crente não nasce a si mesmo; é gerado pelo Espírito. Assim como o nascimento físico não é decisão do bebê, o nascimento espiritual é decisão soberana do Espírito, não do homem."),
QuizQuestion(id:782,question:"O que Paulo diz sobre obedecer aos governantes em Romanos 13:1?",options:["Desobedeça ao governo sempre que possível","'Toda alma seja sujeita às autoridades superiores, porque não há autoridade que não venha de Deus; as autoridades existentes foram estabelecidas por Deus'","Os cristãos estão acima da lei","O governo é sempre inimigo"],correctIndex:1,explanation:"Romanos 13:1-7: Paulo escrevendo sob Nero instrui submissão às autoridades como instrumento da providência divina — não absolutismo (At 5:29: 'obedecer a Deus antes que aos homens') mas disposição geral.",reference:"Romanos 13:1-7",category:.geral,propheticMeaning:"A tensão Romanos 13 (submissão) vs Apocalipse 13 (resistência ao estado que exige adoração) revela que a obediência cristã ao governo é condicional — válida enquanto o Estado exerce função providencial; resistida quando o Estado usurpa o lugar de Deus."),
QuizQuestion(id:783,question:"O que é a 'graça preveniente' segundo João 6:44?",options:["Que todos já foram convertidos","'Ninguém pode vir a mim se o Pai que me enviou não o trouxer' — a graça que precede e possibilita a fé humana, 'prevenindo' (indo antes) a resposta do crente","Que a fé precede a graça","Que a graça é posterior à fé"],correctIndex:1,explanation:"João 6:44: a iniciativa divina que precede a fé humana. Sem o atrair do Pai, ninguém viria a Cristo — a responsabilidade humana (vir) é real mas precedida pela graça divina (trazer).",reference:"João 6:44; João 6:65",category:.geral,propheticMeaning:"A 'atração' do Pai (elkyō — arrastar, atrair com força) é a obra do Espírito que cria a possibilidade da fé. Arminianistas falam de graça preveniente universal; Calvinistas de graça eficaz. Ambos reconhecem que Deus age antes do homem."),
QuizQuestion(id:784,question:"O que é a 'promessa abraâmica' e sua extensão em Gálatas 3?",options:["Uma promessa apenas para Israel","A promessa a Abraão — 'em ti serão benditas todas as nações' (Gn 12:3) — é o evangelho antecipado: cumprida em Cristo (a 'semente' de Abraão) para todos os crentes, judeus e gentios","Uma promessa de terra apenas","Uma promessa temporária revogada no NT"],correctIndex:1,explanation:"Gálatas 3:8,16,29: Paulo identifica a 'semente' de Abraão como Cristo (singular, não plural) e todo crente como filho de Abraão 'pela fé' e herdeiro da promessa.",reference:"Gálatas 3:8,29",category:.geral,propheticMeaning:"'Em ti serão benditas todas as famílias da terra' (Gn 12:3) já era o proto-evangelho — a universalidade da bênção abraâmica. Paulo: 'a Escritura, prevendo que Deus havia de justificar os gentios pela fé, pregou antecipadamente o evangelho a Abraão' (Gl 3:8)."),
QuizQuestion(id:785,question:"O que Paulo ensina sobre a 'armadilha do legalismo' em Colossenses 2:16-23?",options:["Os regulamentos alimentares são obrigatórios","'Não vos deixeis, pois, julgar por causa do que comeis ou bebeis... que são sombra das coisas futuras, mas o corpo é de Cristo' — regulamentos religiosos externos não substituem a realidade em Cristo","As leis cerimoniais permanecem obrigatórias","O legalismo é a segurança da fé"],correctIndex:1,explanation:"Cl 2:16-23: Paulo alerta contra a 'filosofia' colossiana que adicionava regulamentos alimentares, festas, ascetismo e adoração de anjos — 'aparência de sabedoria' mas 'de nenhum valor contra a indulgência da carne.'",reference:"Colossenses 2:16-23",category:.geral,propheticMeaning:"As 'sombras' (dias, meses, festas, alimentos) são válidas enquanto prefiguram — mas se tornam obstáculos quando substituem a realidade que antecidam. Cristo é o 'corpo' (soma — substância) de que as sombras eram projeções."),
QuizQuestion(id:786,question:"O que significa 'arrependimento' (metanoia) no NT?",options:["Apenas sentir tristeza pelo pecado","Mudança de mente e de direção — 'metanoia' (meta = mudança, nous = mente) — a transformação do pensamento sobre Deus, si mesmo e o pecado que resulta em mudança de direção e vida","Penitência religiosa","Uma decisão emocional temporária"],correctIndex:1,explanation:"Arrependimento no NT (Lc 15:7; At 2:38; 17:30): mudança de mentalidade que produz mudança de direção — não apenas emoção mas reorientação da vontade. João Batista exigia 'frutos dignos de arrependimento' (Lc 3:8).",reference:"Atos 2:38; Lucas 15:7",category:.geral,propheticMeaning:"'Metanoia' (mudança de mente) é o oposto da 'metamelomai' de Judas (Gl 27:3 — remorso sem mudança). O arrependimento genuíno muda a relação com Deus e com o pecado — não apenas sentimentos mas direção de vida."),
QuizQuestion(id:787,question:"O que Paulo ensina sobre perdão entre crentes em Efésios 4:32?",options:["O perdão é opcional entre cristãos","'Sede uns para com os outros benignos e compassivos, perdoando-vos uns aos outros como também Deus vos perdoou em Cristo' — o modelo do perdão divino é o padrão do perdão humano","O perdão humano é diferente do divino","Perdoe apenas quem pedir perdão"],correctIndex:1,explanation:"Efésios 4:32: o perdão cristão tem modelo e motivação: como Deus perdoou em Cristo. A graça recebida deve fluir em graça concedida.",reference:"Efésios 4:32; Colossenses 3:13",category:.geral,propheticMeaning:"'Como Deus vos perdoou em Cristo' — a medida do perdão cristão é a medida do perdão divino, que é imensurável. A parábola do servo implacável (Mt 18:23-35) mostra o absurdo de receber perdão ilimitado e não perdoar o limitado."),
QuizQuestion(id:788,question:"O que Paulo ensina sobre a 'morte para o mundo' em Gálatas 6:14?",options:["O crente deve desprezar a criação","'Longe esteja de mim gloriar-me, senão na cruz de nosso Senhor Jesus Cristo, pela qual o mundo está crucificado para mim e eu para o mundo'","O cristão deve isolar-se do mundo","A morte para o mundo é impossível"],correctIndex:1,explanation:"Gálatas 6:14: a cruz como ponto de virada radical — a valorização do mundo (seus sistemas de prestígio, poder e riqueza) morreu quando Paulo morreu com Cristo. Sua glória está apenas na cruz.",reference:"Gálatas 6:14",category:.geral,propheticMeaning:"'O mundo crucificado para mim' é a liberdade da aprovação humana — o que o mundo pode oferecer (status, riqueza, prazer) foi 'morto' pela perspectiva da cruz. O crente só quer 'ganhar Cristo' (Fp 3:8)."),
QuizQuestion(id:789,question:"O que é a parábola do grão de mostarda em Mateus 13:31-32?",options:["Uma parábola sobre oração","O reino dos céus como a menor das sementes que cresce e se torna a maior das hortaliças onde as aves fazem ninhos — o crescimento orgânico e desproporcional do reino a partir de começos humildes","Uma parábola sobre fé pessoal","Uma parábola sobre a Igreja primitiva apenas"],correctIndex:1,explanation:"Mateus 13:31-32: o reino começa em Belém, numa mangueira em Nazaré, com 12 pescadores — e cresce para abarcar toda nação, língua e povo (Ap 7:9). O paradoxo da semente e da árvore.",reference:"Mateus 13:31-32",category:.geral,propheticMeaning:"'As aves fazem ninhos em seus ramos' é linguagem de Daniel 4:12 sobre um grande império que protege as nações — o reino de Cristo crescendo até abarcar todas as nações, cumprindo a promessa de Abraão e a visão de Daniel."),
QuizQuestion(id:790,question:"O que Jesus ensinou sobre a oração persistente na parábola da viúva (Lucas 18:1-8)?",options:["Ore uma vez e pare","A viúva que persistiu até o juiz injusto ceder; Jesus conclui: 'Deus não fará justiça aos seus eleitos que clamam a ele dia e noite?' — modelo de perseverança na oração","A oração repetida é superstição","Deus responde apenas na primeira oração"],correctIndex:1,explanation:"Lucas 18:1-8: Jesus contou a parábola 'para que devemos orar sempre e não desfalecer.' A viúva persistente como modelo — se o juiz injusto cede, quanto mais o Pai amoroso ouvirá seus filhos.",reference:"Lucas 18:1-8",category:.geral,propheticMeaning:"'Quando o Filho do Homem vier, achará fé na terra?' (Lc 18:8) liga a oração persistente à escatologia — a perseverança na oração é evidência de fé que aguarda a vinda do Senhor. Oração persistente = fé que não desiste."),
QuizQuestion(id:791,question:"O que Paulo ensina sobre a corrida cristã em 1 Coríntios 9:24-27?",options:["A vida cristã é casual","'Não sabeis que os que correm no estádio todos correm, mas um só leva o prêmio? Correi de tal maneira que o alcanceis' — Paulo usando imagens olímpicas para descrever disciplina espiritual","A vitória é garantida sem esforço","A corrida cristã é apenas espiritual"],correctIndex:1,explanation:"1 Co 9:24-27: Paulo disciplina seu corpo como atleta — 'maltrato meu corpo e o sujeito à servidão, para que, tendo pregado aos outros, eu mesmo não venha a ser reprovado.'",reference:"1 Coríntios 9:24-27",category:.geral,propheticMeaning:"Paulo temendo ser 'reprovado' (adokimos — reprovado no teste) não é insegurança sobre a salvação mas sobre a recompensa e a consistência — o pregador que preza a aprovação de Deus acima da de homens."),
QuizQuestion(id:792,question:"O que é a 'esposa de Cristo' em Efésios 5:25-32?",options:["Uma metáfora menor","A Igreja como esposa de Cristo — Cr's amor pela Igreja como modelo para maridos: 'Maridos, amai vossas mulheres, como Cristo amou a Igreja e a si mesmo se entregou por ela'","Os anjos no céu","Israel apenas"],correctIndex:1,explanation:"Efésios 5:25-32: a Igreja como esposa de Cristo é o 'grande mistério' — a analogia mais profunda do NT para o amor conjugal e o amor de Cristo.",reference:"Efésios 5:25-32",category:.geral,propheticMeaning:"As bodas do Cordeiro (Ap 19:7-9) são a consumação do que Ef 5 anuncia — o noivado em Cristo, a vida de santificação como preparação nupcial, e a consumação na nova criação. A história da redenção é história de amor."),
QuizQuestion(id:793,question:"O que Paulo ensina sobre a 'circuncisão do coração' em Romanos 2:28-29?",options:["A circuncisão física é suficiente","'O verdadeiro judeu não é o que o é exteriormente... mas o que o é interiormente, e circuncisão é a do coração, pelo Espírito, não pela letra'","A circuncisão foi abolida completamente sem substituto","Apenas os não-circuncidados são salvos"],correctIndex:1,explanation:"Rm 2:28-29: Paulo antecipa Deuteronômio 30:6 — a circuncisão do coração que Moisés prometeu é realizada pelo Espírito na nova aliança.",reference:"Romanos 2:28-29; Deuteronômio 30:6",category:.geral,propheticMeaning:"A circuncisão do coração (Dt 30:6; Jr 4:4; Rm 2:29) é a dimensão interior da aliança que o rito externo simbolizava — o Espírito cortando a 'carne' da natureza pecaminosa, não apenas o prepúcio físico."),
QuizQuestion(id:794,question:"O que Tiago 2:14-17 diz sobre fé sem obras?",options:["A fé sem obras ainda salva","'De que aproveitará se alguém disser que tem fé, e não tiver obras? Pode essa fé salvá-lo?... Assim também a fé, se não tiver obras, é morta em si mesma'","As obras são mais importantes que a fé","Obras e fé são igualmente necessárias para justificação"],correctIndex:1,explanation:"Tiago 2:14-17: fé sem obras é morta — como compaixão que não alimenta o faminto não é compaixão real. A fé genuína produz obras; obras sem fé não salvam; fé sem obras é demonstravelmente falsa.",reference:"Tiago 2:14-17",category:.geral,propheticMeaning:"Tiago provando a fé pelas obras (Tg 2:18) é como João provando o amor (1 Jo 3:17-18) — o amor e a fé são invisíveis interiormente mas se tornam visíveis exteriormente. A árvore é conhecida pelo fruto."),
QuizQuestion(id:795,question:"O que é o 'testemunho' (marturia) na teologia joanina?",options:["Apenas relato legal","O testemunho em João é multifacetado: João Batista testificou (Jo 1:34), as obras de Jesus testificaram (Jo 5:36), o Pai testificou (Jo 5:37), as Escrituras testificam (Jo 5:39), o Espírito testifica (Jo 15:26), os discípulos testificam (Jo 15:27)","O testemunho é apenas sobre o passado","Apenas os apóstolos testificam"],correctIndex:1,explanation:"João usa 'marturia/martureō' (~47 vezes) — testemunho convergente apontando para a identidade de Jesus. A condenação dos que não creem é que a evidência era suficiente mas foi rejeitada (Jo 3:19).",reference:"João 5:31-39",category:.geral,propheticMeaning:"O Espírito como testemunha (Jo 15:26-27) com os discípulos é a estrutura da missão: o Espírito testifica interiormente ao ouvinte enquanto os discípulos testificam externamente. A evangelização é testemunho duplo."),
QuizQuestion(id:796,question:"O que é a 'transfiguração' de Jesus em Mateus 17?",options:["Um sonho dos discípulos","Jesus foi transfigurado diante de Pedro, Tiago e João — seu rosto brilhou como o sol, suas vestes foram brancas como luz, Moisés e Elias apareceram e a voz do Pai falou: 'Este é o meu Filho amado'","Uma visão apenas simbólica","Uma aparição após a ressurreição"],correctIndex:1,explanation:"Mateus 17:1-8: a transfiguração revelou a glória divina de Cristo velada na encarnação — antecipação da glória da segunda vinda. Pedro quis fazer tendas (permanecer); a nuvem e a voz do Pai os redirecionaram.",reference:"Mateus 17:1-8; 2 Pedro 1:16-18",category:.geral,propheticMeaning:"Moisés (lei) e Elias (profetas) conversando com Jesus confirma que ele é a meta de ambos. A voz do Pai repetindo o batismo ('Filho amado — ouvi-o') transfere a autoridade profético-legal para Cristo: 'a ele ouvi.'"),
QuizQuestion(id:797,question:"O que Paulo diz sobre a ressurreição como fundamento do evangelho em 1 Coríntios 15:14?",options:["A ressurreição é opcional","'Se Cristo não ressuscitou, é vã a nossa pregação e vã a vossa fé... seríeis ainda os vossos pecados'","A ressurreição é apenas simbólica","A ressurreição é tema secundário"],correctIndex:1,explanation:"1 Co 15:14-19: Paulo lista as implicações de se a ressurreição não ocorreu — pregação vã, fé vã, falsos testemunhos, pecados sem perdão, mortos perdidos, cristãos 'mais digno de compaixão que todos os homens.'",reference:"1 Coríntios 15:14-19",category:.geral,propheticMeaning:"A ressurreição não é detalhe apologético — é o eixo de tudo. Sem ela, o evangelho colapsa completamente. Paulo não hesita: 'se Cristo não ressuscitou' é a hipótese que destruiria toda a fé cristã."),
QuizQuestion(id:798,question:"O que Paulo ensina sobre o 'amor de Cristo que nos constrange' em 2 Coríntios 5:14?",options:["Que o amor nos força literalmente","'O amor de Cristo nos constrange (synechei — nos compele, nos pressiona), porque julgamos assim: um morreu por todos... para que os que vivem não vivam mais para si'","Que o amor é obrigação legal","Que somos forçados a servir"],correctIndex:1,explanation:"2 Co 5:14-15: o amor de Cristo (expresso na morte vicária) é a força que motiva e orienta toda a vida e ministério de Paulo — não obrigação mas compulsão de amor.",reference:"2 Coríntios 5:14-15",category:.geral,propheticMeaning:"'Não mais para si mesmos, mas para aquele que por eles morreu e ressuscitou' — a motivação do ministério cristão: não salvar almas para encher igrejas, mas por compulsão de amor ao Cristo que morreu e de compaixão pelos que ele veio salvar."),
QuizQuestion(id:799,question:"O que é o 'descanso sabático' espiritual em Hebreus 4:9-11?",options:["O sábado literalmente","'Resta, pois, um repouso sabático para o povo de Deus... procurai, pois, entrar naquele descanso' — o descanso escatológico em Cristo, participação no descanso de Deus","O descanso após a morte","O domingo como dia de repouso literal"],correctIndex:1,explanation:"Hebreus 4:9-11: o 'sabbatismos' que resta para o povo de Deus é o descanso escatológico antecipado na fé — cessar das obras próprias assim como Deus descansou das suas obras.",reference:"Hebreus 4:9-11",category:.geral,propheticMeaning:"O descanso sabático tipológico (Canaã, sábado) aponta para o descanso definitivo em Cristo — 'quem entrou no repouso de Deus, também ele descansou das suas obras' (Hb 4:10). Confiar em Cristo é entrar no descanso divino."),
QuizQuestion(id:800,question:"Quais são os três testes da vida cristã segundo 1 João?",options:["Batismo, comunhão e diezmo","Crença correta sobre Cristo (teste doutrinário), amor fraternal (teste moral/relacional) e obediência aos mandamentos (teste ético) — os três critérios que asseguram que temos a vida eterna","Arrependimento, batismo e consagração","Oração, jejum e esmolas"],correctIndex:1,explanation:"1 João usa três testes recorrentes para assegurar a genuinidade da vida espiritual: cristologia correta (quem é Jesus), amor aos irmãos, e obediência à Palavra.",reference:"1 João 2:3-6; 3:14; 4:2-3",category:.geral,propheticMeaning:"Os três testes de João formam um 'tripé' — todos três devem estar presentes. Boa doutrina sem amor é farisaísmo; amor sem doutrina é sentimentalismo; obediência sem amor é legalismo. Juntos, definem a vida cristã autêntica."),
QuizQuestion(id:801,question:"O que Paulo diz sobre a glória futura em Romanos 8:18?",options:["O sofrimento presente é insuportável","'As aflições do tempo presente não são para se compararem com a glória que em nós há de ser revelada' — perspectiva que transforma o sofrimento presente","O sofrimento anula a glória futura","A glória futura é incerta"],correctIndex:1,explanation:"Rm 8:18: a comparação entre sofrimento presente e glória futura — o peso eterno da glória (2 Co 4:17) supera incomparavelmente as aflições temporais.",reference:"Romanos 8:18",category:.geral,propheticMeaning:"Paulo que sofreu naufrágio, prisão, açoites e lapidação escreveu 'não são para se compararem' — não trivializando o sofrimento mas revelando que a perspectiva da glória eterna transforma a relação com o sofrimento temporal."),
QuizQuestion(id:802,question:"O que é o 'julgamento do trono branco' em Apocalipse 20:11-15?",options:["Um julgamento apenas de inimigos de Israel","O julgamento final de todos os mortos — 'os livros foram abertos, e outro livro foi aberto, o livro da vida; e os mortos foram julgados pelas coisas escritas nos livros'","O julgamento dos anjos apenas","Um julgamento apenas para pecadores da Igreja"],correctIndex:1,explanation:"Apocalipse 20:11-15: o julgamento universal pós-ressurreição — todos os mortos diante do trono branco, julgados por suas obras, e os cujos nomes não estão no livro da vida lançados no lago de fogo.",reference:"Apocalipse 20:11-15",category:.geral,propheticMeaning:"Os 'livros' (obras) e o 'livro da vida' (graça) no julgamento final revelam dupla base: nenhuma obra seria suficiente — todos precisam ter o nome no livro da vida. As obras revelam o coração; o livro da vida revela a graça."),
QuizQuestion(id:803,question:"O que é a 'árvore da vida' em Gênesis 2-3 e Apocalipse 22?",options:["Uma árvore física apenas","Em Gênesis 2, a árvore da vida no jardim foi bloqueada após a queda. Em Apocalipse 22:2, a árvore da vida restaurada na nova Jerusalém produz fruto todos os meses e suas folhas curam as nações","Um símbolo sem significado","Uma árvore mágica"],correctIndex:1,explanation:"Gênesis 2:9; 3:22-24; Apocalipse 22:2,14: a árvore da vida é inclusão — perdida na Queda, restaurada na nova criação. O acesso à árvore é o acesso à vida eterna.",reference:"Gênesis 2:9; Apocalipse 22:2",category:.genesis,propheticMeaning:"A inclusão narrativa da Bíblia: jardim (Gn 2)→novo jardim (Ap 22). Árvore da vida bloqueada (Gn 3:24)→árvore da vida acessível (Ap 22:14). A Cruz entre esses dois momentos é a 'árvore da vida' através da qual o acesso é restaurado."),
QuizQuestion(id:804,question:"O que Paulo ensina sobre 'tomai toda a armadura' em Efésios 6:13?",options:["É uma metáfora opcional","'Portanto, tomai toda a armadura de Deus, para que possais resistir no dia mau e, depois de terdes vencido tudo, ficar firmes' — a plenitude da proteção divina necessária para a guerra espiritual","Apenas para líderes espirituais","A armadura é apenas defensiva"],correctIndex:1,explanation:"Efésios 6:13: 'toda' a armadura — nenhuma peça pode ser omitida. O dia mau vem; a preparação deve ser completa.",reference:"Efésios 6:13-17",category:.geral,propheticMeaning:"'Depois de terdes vencido tudo, ficar firmes' — o objetivo da armadura é manter a posição conquistada em Cristo, não conquistar nova posição. A batalha espiritual é manter o que já é verdade sobre o crente em Cristo."),
QuizQuestion(id:805,question:"Qual é a oração pelo 'pão nosso de cada dia' no Pai Nosso?",options:["Oração por riqueza","'O pão nosso de cada dia dá-nos hoje' — pedido de provisão diária, dependência de Deus para as necessidades básicas, eco do maná no deserto (provisão diária, não acumulação)","Oração pela Ceia do Senhor apenas","Oração metafórica sem sentido literal"],correctIndex:1,explanation:"Mateus 6:11: 'epiousion' (pão necessário/do dia seguinte) — o pedido de provisão adequada diária, não acumulação. Reflete Provérbios 30:8 e o maná no deserto.",reference:"Mateus 6:11; Êxodo 16:4",category:.geral,propheticMeaning:"O pedido diário (não semanal ou anual) expressa dependência consciente e confiante de Deus como provedor. O maná dado dia por dia (Êx 16) ensinava Israel a depender diariamente, não de estoques próprios — o mesmo princípio no Pai Nosso."),
QuizQuestion(id:806,question:"O que é a 'tentação' no Pai Nosso ('não nos deixes cair em tentação')?",options:["Deus nos tenta ao pecado","O pedido de proteção divina nos momentos de teste e tentação — 'não nos deixes entrar em provação além do que podemos suportar' (1 Co 10:13). Deus não tenta (Tg 1:13) mas pode permitir testagens","Pedido de nunca ser testado","O pedido de uma vida sem dificuldades"],correctIndex:1,explanation:"Mateus 6:13: 'não nos deixes entrar em tentação/provação' — submissão à soberania divina sobre os testes da fé, pedindo misericórdia e proteção. Deus não tenta ao mal (Tg 1:13) mas pode conduzir ao deserto como fez com Jesus (Mt 4:1).",reference:"Mateus 6:13; Tiago 1:13",category:.geral,propheticMeaning:"O Getsêmani é Jesus aplicando o Pai Nosso à sua própria crise: 'se possível passe este cálice' (livre do teste) 'mas não como eu quero' (submissão à vontade divina). O modelo perfeito da petição do Pai Nosso."),
QuizQuestion(id:807,question:"O que significa 'perder a vida para salvá-la' em Mateus 16:25?",options:["Suicídio ou martírio literal","'Quem quiser salvar a sua vida perdê-la-á; mas quem perder a sua vida por causa de mim achá-la-á' — a lei paradoxal do reino: a auto-preservação leva à perda real; a entrega a Cristo leva à vida verdadeira","Uma parábola sem aplicação","Missão apenas para mártires"],correctIndex:1,explanation:"Mateus 16:25: o paradoxo da cruz aplicado à vida cotidiana — a psuchē (alma/vida) que se agarra a si mesma é perdida; a que se entrega a Cristo é encontrada na eternidade.",reference:"Mateus 16:25",category:.geral,propheticMeaning:"'Perder a vida' (psuchēn) por Cristo não é apenas martírio mas a negação diária do eu — 'tome a sua cruz diariamente' (Lc 9:23). A morte do eu não é o fim mas o início da vida verdadeira em Cristo."),
QuizQuestion(id:808,question:"O que foi o 'pecado imperdoável' contra o Espírito Santo?",options:["Um erro doutrinário específico","A atribuição da obra do Espírito Santo ao diabo — blasfêmia que Jesus mencionou quando os fariseus atribuíram suas obras a Belzebu. É imperdoável não porque Deus não quer perdoar, mas porque quem o comete não se arrepende","O pecado de adultério","O abandono da fé uma vez"],correctIndex:1,explanation:"Mateus 12:31-32: 'todo pecado e blasfêmia será perdoado aos homens, mas a blasfêmia contra o Espírito não será perdoada.' O contexto é os fariseus atribuindo milagres de Jesus a Satanás.",reference:"Mateus 12:31-32",category:.geral,propheticMeaning:"O pecado 'imperdoável' é a resistência permanente e endurecida ao Espírito que convence do pecado e aponta para Cristo. A pessoa que o cometeu é aquela que não pode arrepender-se por ter apagado o mecanismo do arrependimento."),
QuizQuestion(id:809,question:"O que Paulo ensina sobre a 'irmandade universal em Cristo' em Colossenses 3:11?",options:["Apenas judeus têm plena cidadania","'Não há grego nem judeu, circuncisão nem incircuncisão, bárbaro, cita, escravo, livre; mas Cristo é tudo e em todos' — a identidade em Cristo supera e unifica toda divisão humana","As diferenças culturais desaparecem","A unidade em Cristo é apenas espiritual"],correctIndex:1,explanation:"Colossenses 3:11: as divisões mais profundas do mundo antigo (étnicas, religiosas, culturais, de classe) são superadas pela identidade comum em Cristo.",reference:"Colossenses 3:11; Gálatas 3:28",category:.geral,propheticMeaning:"'Cristo é tudo em todos' — a identidade em Cristo é mais fundamental que qualquer identidade humana. A Igreja multicultural não é projeto humano mas resultado da obra de Cristo que derrubou 'o muro da separação' (Ef 2:14)."),
QuizQuestion(id:810,question:"Qual é o ensinamento de João sobre 'permanecer em Cristo' em João 15:4-5?",options:["Permanecer é opcional","'Permanecei em mim e eu em vós. Como o ramo não pode dar fruto de si mesmo, se não permanecer na videira, assim também vós, se não permanecerdes em mim... sem mim nada podeis fazer'","Permanecer é apenas para apóstolos","Permanecer é o mesmo que frequentar a Igreja"],correctIndex:1,explanation:"João 15:4-5: a videira e os ramos — a vida espiritual não vem do esforço dos ramos mas da conexão com a videira. Sem Cristo, o crente não pode produzir nada de valor eterno.",reference:"João 15:4-5",category:.geral,propheticMeaning:"'Sem mim nada podeis fazer' (v.5) não é pessimismo mas libertação — o crente é liberado do fardo de tentar produzir fruto pela própria força e convidado a permanecer na conexão vital com Cristo, que produz o fruto."),
QuizQuestion(id:811,question:"O que Paulo diz sobre a vida e a morte como 'ganho' em Filipenses 1:21?",options:["A morte é terrível para o cristão","'Para mim o viver é Cristo e o morrer é lucro' — Paulo vê tanto a vida (fruto do trabalho para Cristo) quanto a morte (ganhar plenamente Cristo) como vitória; 'é melhor partir e estar com Cristo'","A morte não é ganho","A vida presente é sempre melhor que a morte"],correctIndex:1,explanation:"Fp 1:21-23: Paulo em prisão vê tanto viver (para a Igreja) quanto morrer (para estar com Cristo) como 'ganho.' A morte para o crente é 'partir para estar com Cristo, o que é muito melhor.'",reference:"Filipenses 1:21-23",category:.geral,propheticMeaning:"'O viver é Cristo' — não a vida, nem a família, nem o ministério: é Cristo. Quando Cristo é a vida, a morte não pode roubar nada — apenas revela mais plenamente o que já era o tesouro da vida. A morte perde seu terror."),
QuizQuestion(id:812,question:"O que João revela sobre a oração 'em meu nome' em João 14:13-14?",options:["Uma fórmula mágica para orar","'Tudo o que pedirdes em meu nome, eu o farei, para que o Pai seja glorificado no Filho' — orar 'em nome de Jesus' é orar de acordo com sua vontade e caráter, alinhados com seus propósitos","Uma garantia de que qualquer pedido é concedido","Uma oração que elimina a necessidade de fé"],correctIndex:1,explanation:"João 14:13-14; 15:16; 16:23-24: a repetição da promessa de orar 'em meu nome' — não uma senha mágica mas alinhamento com os propósitos de Cristo, para a glória do Pai.",reference:"João 14:13-14",category:.geral,propheticMeaning:"'Em meu nome' (en tō onomati mou) é o equivalente a 'conforme a quem sou e o que quero.' Assim como agir 'em nome do rei' era agir segundo a autoridade e vontade do rei, orar em nome de Cristo é submeter o pedido ao seu filtro."),
QuizQuestion(id:813,question:"Qual é o tema principal do livro de Habacuque?",options:["O exílio babilônico","O profeta que questiona Deus: 'Por que tolerastes os traidores e te calas quando o ímpio engole o mais justo do que ele?' — e recebe a resposta que 'o justo viverá pela sua fé'","A reconstrução do templo","O regresso do exílio"],correctIndex:1,explanation:"Habacuque é um diálogo entre o profeta que questiona a injustiça (por que Deus usa os babilônios?) e Deus que responde com a visão e a resposta da fé. Culmina em louvor (Hc 3).",reference:"Habacuque 1:2-4; 2:4; 3:17-19",category:.profetas,propheticMeaning:"'Ainda que a figueira não floresça' (Hc 3:17-19) — Habacuque chegou à fé que louva Deus sem as circunstâncias favoráveis. É a fé mais madura: não 'Deus me abençoará,' mas 'Deus é minha força mesmo sem a bênção.'"),
QuizQuestion(id:814,question:"Qual é a promessa de Jeremias 29:11 no contexto do exílio?",options:["Uma promessa de retorno imediato","'Porque eu sei os planos que tenho a vosso respeito, diz o Senhor, planos de paz e não de mal, para vos dar um futuro e uma esperança' — dito aos exilados na Babilônia que deveriam esperar 70 anos","Uma promessa para todos os crentes individualmente","Uma promessa sem contexto histórico"],correctIndex:1,explanation:"Jeremias 29:11 foi dito aos exilados em Babilônia que queriam retorno imediato — Deus os instrui a construir casas, plantar jardins, e buscar a paz da cidade durante 70 anos antes do retorno.",reference:"Jeremias 29:4-14",category:.profetas,propheticMeaning:"O contexto importa: a promessa de Jr 29:11 veio junto com a instrução de buscar o bem da Babilônia (v.7) — não fuga do mundo, mas presença transformadora no exílio. O crente no 'exílio' do mundo deve engajar o mundo para seu bem."),
QuizQuestion(id:815,question:"O que é a 'nova aliança' profetizada por Jeremias 31:31-34?",options:["Uma renovação da lei de Moisés","'Farei nova aliança com a casa de Israel... porei a minha lei no seu íntimo e a escreverei no seu coração... perdoarei as suas iniquidades e nunca mais me lembrarei dos seus pecados'","Uma aliança apenas para o futuro distante","Uma aliança política com Israel"],correctIndex:1,explanation:"Jeremias 31:31-34 é a única referência explícita a 'nova aliança' no AT. Hebreus 8:6-13 cita integralmente como cumprido em Cristo.",reference:"Jeremias 31:31-34; Hebreus 8:6-13",category:.profetas,propheticMeaning:"A nova aliança tem quatro características (Jr 31:33-34): lei no coração, todos conhecendo a Deus, perdão total, e relação direta. Em Cristo, todas são cumpridas: o Espírito escreve a lei (2 Co 3:3), todos têm acesso ao Pai (Jo 14:6), e o perdão é completo (Hb 10:17-18)."),
QuizQuestion(id:816,question:"O que foi o 'vale dos ossos secos' na visão de Ezequiel 37?",options:["Um cemitério real que Ezequiel visitou","Deus mostrou a Ezequiel um vale cheio de ossos secos — perguntou: 'Podem estes ossos viver?' Ao profetizar, os ossos se juntaram, ganharam carne e o Espírito entrou neles — símbolo da ressurreição de Israel","Uma profecia sobre a ressurreição física geral","Uma narrativa sem significado espiritual"],correctIndex:1,explanation:"Ezequiel 37:1-14: a visão dos ossos secos é metáfora da nação de Israel no exílio ('nossos ossos estão secos, nossa esperança perdida' — v.11). A profecia de restauração nacional mediante o Espírito.",reference:"Ezequiel 37:1-14",category:.profetas,propheticMeaning:"A pergunta divina 'Podem estes ossos viver?' convida Ezequiel a declará-la impossível (humanamente) mas possível (para Deus). A resposta 'Senhor Deus, tu o sabes' é fé que não nega a realidade mas confia no Deus que ressuscita mortos."),
QuizQuestion(id:817,question:"Qual foi a missão de Daniel na corte babilônica?",options:["Recusar toda participação na cultura babilônica","Daniel e seus três amigos foram levados para treinamento na corte de Nabucodonosor; mantiveram fidelidade a Deus recusando alimentos impuros, e Deus os abençoou com sabedoria dez vezes maior","Abandonar a fé judaica","Tornar-se completamente babilônico"],correctIndex:1,explanation:"Daniel 1: Daniel e seus companheiros negociaram com o chefe dos eunucos para não comer os alimentos do rei — e foram abençoados com saúde e sabedoria superior à dos outros conselheiros.",reference:"Daniel 1:8-20",category:.profetas,propheticMeaning:"Daniel mantendo fidelidade enquanto serve excelentemente na cultura pagã é modelo de 'encarnação cultural' — presente na cultura sem ser moldado por ela. Não isolamento (os hebreus não fugiram) nem assimilação (não comeram os alimentos), mas fidelidade engajada."),
QuizQuestion(id:818,question:"O que é a 'fé como dom de Deus' em Efésios 2:8?",options:["Que geramos a fé por esforço","'Pela graça sois salvos, mediante a fé; e isso não vem de vós, é dom de Deus' — a fé que salva não é realizção humana mas dom divino","Que a fé é o elemento humano da salvação apenas","A graça é de Deus mas a fé é nossa contribuição"],correctIndex:1,explanation:"Efésios 2:8: 'isso não vem de vós' — o pronome neutro em grego se refere ao conjunto todo (graça + fé), não apenas à graça. A fé em si é parte do dom divino.",reference:"Efésios 2:8-9",category:.geral,propheticMeaning:"Se a fé fosse contribuição humana, alguém poderia se gloriar de ter tido fé enquanto outros não tiveram. Mas Ef 2:9 ('não por obras, para que ninguém se glorie') exclui qualquer glorificação humana — incluindo a da fé como esforço próprio."),
QuizQuestion(id:819,question:"O que o Salmo 22 profetiza sobre a crucificação?",options:["Uma oração do sofrimento de Davi apenas","Davi escreveu 1.000 anos antes os detalhes: 'Meu Deus, por que me abandonaste' (Mt 27:46); 'perfuraram minhas mãos e pés' (v.16); 'dividem minhas vestes' (v.18); 'escárneo e zombaria' dos que passam (v.7-8)","Apenas uma metáfora","Uma profecia sobre o exílio"],correctIndex:1,explanation:"Salmo 22: a precisão dos detalhes da crucificação escritos mil anos antes é notável — crucificação não existia na época de Davi, mas o Espírito guiou sua escrita proféctica.",reference:"Salmos 22:1,7-8,16,18; Mateus 27:35-46",category:.profetas,propheticMeaning:"O Salmo 22 começa com abandono ('Deus meu, por que me abandonaste') e termina com vitória ('proclamarão a sua justiça' — v.31). Jesus na cruz recitou o início; a ressurreição cumpriu o final. O Salmo inteiro é a paixão de Cristo."),
QuizQuestion(id:820,question:"O que foi a 'parede de separação' que Cristo derrubou segundo Efésios 2:14?",options:["Uma parede do templo","A barreira que separava judeus e gentios — 'ele derrubou o muro de separação, a inimizade', criando 'um só homem novo' pela sua carne — referência tanto à lei cerimonial quanto à hostilidade real","Uma divisão política entre nações","Uma barreira entre a Igreja e o Estado"],correctIndex:1,explanation:"Efésios 2:14-16: o 'muro do meio' que separava judeus e gentios (literalmente, a parede do templo que separava o átrio dos gentios) foi derrubado em Cristo, criando 'um novo homem.'",reference:"Efésios 2:14-16",category:.geral,propheticMeaning:"No templo de Herodes havia literalmente uma parede com inscrição grega e latina proibindo gentios sob pena de morte. Cristo derrubando esse muro é a mais radical inclusividade — 'não há distinção' (Rm 3:22) entre judeu e gentio diante da cruz."),
QuizQuestion(id:821,question:"O que Paulo ensina sobre a 'ira divina' em Romanos 1:18?",options:["Deus não tem ira","'A ira de Deus se revela do céu contra toda impiedade e injustiça dos homens que detêm a verdade em injustiça' — a ira como reação justa e santa de Deus contra o pecado","A ira é apenas humana","Deus está sempre com raiva dos humanos"],correctIndex:1,explanation:"Rm 1:18-32: a ira divina (orgē) é a resposta santa e justa de Deus ao pecado — revela-se tanto no presente (entregando o pecador às consequências) quanto no futuro (julgamento final).",reference:"Romanos 1:18",category:.geral,propheticMeaning:"A ira de Deus não é capricho emocional mas a reação necessária da santidade contra a impiedade — a mesma perfeição que o amor é também a ira. Sem a ira divina, a propiciação (Rm 3:25) seria desnecessária e sem sentido."),
QuizQuestion(id:822,question:"O que é a 'teologia da cruz' (Theologia Crucis) de Lutero baseada em Paulo?",options:["Teologia baseada apenas no poder","A interpretação do evangelho através da cruz — Deus se revela na fraqueza e humilhação (a cruz), não na glória e poder (Theologia Gloriae). '1 Co 1:18: a palavra da cruz é poder de Deus'","A teologia do sofrimento apenas","Uma teologia apenas medieval"],correctIndex:1,explanation:"Baseada em 1 Co 1-2: Deus escolheu revelar-se através do escândalo da cruz, não através de poder, sabedoria ou glória terrenas. A fraqueza de Deus é mais forte que a força humana.",reference:"1 Coríntios 1:18,25",category:.geral,propheticMeaning:"A teologia da cruz protege contra a 'teologia da glória' que espera Deus apenas em bênçãos, saúde e sucesso — e leva à decepção quando a cruz vem. O cristão encontra Deus especialmente nos pontos de fraqueza e sofrimento (2 Co 12:9)."),
QuizQuestion(id:823,question:"O que Paulo ensina sobre 'andar em amor' em Efésios 5:1-2?",options:["O amor é apenas sentimento","'Sede imitadores de Deus... e andai em amor, como também Cristo nos amou e se entregou por nós, oferta e sacrifício a Deus'  — amor como estilo de vida sacrificial à imagem de Cristo","O amor é obrigação religiosa","O amor é uma devoção interna apenas"],correctIndex:1,explanation:"Ef 5:1-2: o amor não é opcional nem apenas emocional — é caminhar (peripatein) no modo de existência de Cristo que se entregou como sacrifício. O modelo é a auto-entrega de Cristo.",reference:"Efésios 5:1-2",category:.geral,propheticMeaning:"'Oferta e sacrifício de agradável odor a Deus' — Paulo descrevendo a morte de Cristo com linguagem sacrificial do AT confirma que a cruz não foi apenas moral, mas propiciatória: satisfazendo os requisitos da santidade divina."),
QuizQuestion(id:824,question:"O que Paulo ensina sobre a 'redenção do tempo' em Efésios 5:16?",options:["Trabalhe o máximo possível","'Resgatai o tempo, porque os dias são maus' — aproveitar cada oportunidade (kairon — o momento certo) para o bem e a glorificação de Deus, não desperdiçando o tempo em futilidades","Medite durante todo o tempo livre","Faça o que quiser com seu tempo"],correctIndex:1,explanation:"Ef 5:16: 'redimir o tempo' (exagorazomenoi ton kairon) — comprar de volta cada oportunidade, consciente de que os dias são maus e o tempo é precioso.",reference:"Efésios 5:16",category:.geral,propheticMeaning:"O tempo 'mal' (ponēros — mau, corrupto) do mundo torna cada momento favorável ao evangelho e ao bem uma oportunidade que não se repete. A consciência escatológica ('o fim está próximo') gera urgência no uso do tempo."),
QuizQuestion(id:825,question:"O que é a 'pedagogia da graça' em Tito 2:11-12?",options:["Que a lei ensina mais que a graça","'A graça de Deus que traz salvação se manifestou a todos os homens, ensinando-nos a negar a impiedade e as concupiscências mundanas e a viver sensata, justa e piamente'","A graça não ensina nada","A graça apenas perdoa, não ensina"],correctIndex:1,explanation:"Tito 2:11-12: a graça não apenas salva — ela ensina e disciplina. A graça é um mestre que produz caráter ético: rejeição da impiedade e vida justa. Graça e ética são inseparáveis.",reference:"Tito 2:11-12",category:.geral,propheticMeaning:"'A graça que ensina' contradiz a ideia de que a graça é permissiva — ela é o mais severo mestre, pois apela ao amor e à gratidão, motivações mais profundas que o medo da punição. A graça que não transforma não foi realmente recebida."),
QuizQuestion(id:826,question:"O que Paulo diz sobre a 'boa consciência' em 1 Timóteo 1:5?",options:["A consciência é irrelevante para o cristão","'O fim do preceito é o amor proveniente de coração puro, e de boa consciência e de fé sem fingimento' — a consciência pura como parte da tripla raiz do amor genuíno","A consciência deve ser ignorada","Apenas a doutrina importa, não a consciência"],correctIndex:1,explanation:"1 Timóteo 1:5: Paulo apresenta a tríade de coração puro, boa consciência e fé sincera como a raiz do amor genuíno — o antídoto ao ensino que gera apenas 'disputas' (v.4).",reference:"1 Timóteo 1:5",category:.geral,propheticMeaning:"'Boa consciência' (agathēs syneidēseōs) é a consciência formada pela Palavra e mantida pela confissão e perdão — não perfectionism moral, mas integridade interior que não vive em contradição entre o que crê e o que faz."),
QuizQuestion(id:827,question:"O que é a 'paciência' (hypomonē) no NT?",options:["Tolerância passiva","Perseverança ativa — capacidade de 'permanecer sob' (hypo + menō) o peso das circunstâncias difíceis, suportando-as com confiança em Deus; Rm 5:3-4 a coloca como produtora de caráter e esperança","Esperar sem agir","Uma virtude apenas monástica"],correctIndex:1,explanation:"Hypomonē (perseverança/paciência) não é resignação passiva mas agência ativa sob pressão — Rm 5:3-4; Tg 1:3-4; Hb 12:1. Os heróis da fé (Hb 11) perseveraram.",reference:"Romanos 5:3-4; Hebreus 12:1",category:.geral,propheticMeaning:"A perseverança cristã não é produto do temperamento humano mas do Espírito e da esperança — 'perseveramos pelas consolações das Escrituras e pela paciência' (Rm 15:4). A Palavra de Deus é o recurso para perseverar."),
QuizQuestion(id:828,question:"O que Paulo ensina sobre a 'paz de Cristo' em Colossenses 3:15?",options:["A paz elimina todo conflito","'A paz de Cristo governe em vossos corações, para a qual também fostes chamados em um só corpo, e sede agradecidos' — a paz como árbitro das decisões e relações na Igreja","A paz é apenas ausência de conflito","Apenas líderes têm a paz de Cristo"],correctIndex:1,explanation:"Cl 3:15: 'governe' (brabeuetō — arbitre, atue como árbitro) a paz de Cristo — não apenas sentimento mas princípio que resolve conflitos e guia decisões na comunidade.",reference:"Colossenses 3:15",category:.geral,propheticMeaning:"A paz de Cristo como árbitro (da mesma raiz de 'prêmio' em At 17) nas relações comunitárias contrasta com o domínio da ansiedade, competição ou orgulho. A paz de Deus 'guarda corações' (Fp 4:7) e 'governa corações' (Cl 3:15)."),
QuizQuestion(id:829,question:"O que significa 'Maranata' (1 Coríntios 16:22)?",options:["Aleluia em aramaico","'Nosso Senhor vem' (marana tha em aramaico) ou 'nosso Senhor, vem!' — uma das orações mais antigas da Igreja cristã, encontrada também em Apocalipse 22:20 ('Vem, Senhor Jesus')","Uma maldição","Uma bênção sacerdotal"],correctIndex:1,explanation:"1 Co 16:22: 'Maranata' em aramaico revela que os primeiros cristãos (de língua aramaica) aguardavam ansiosamente a vinda do Senhor.",reference:"1 Coríntios 16:22; Apocalipse 22:20",category:.geral,propheticMeaning:"'Maranata' como encerramento de carta revela que a segunda vinda não era tema teológico abstrato mas esperança viva que moldava a vida diária. 'Vem, Senhor Jesus' é a oração escatológica de toda a Igreja."),
QuizQuestion(id:830,question:"O que é a 'vida eterna' segundo João 17:3?",options:["Uma duração temporal infinita apenas","'Esta é a vida eterna: que te conheçam a ti, o único Deus verdadeiro, e aquele que enviaste, Jesus Cristo' — a vida eterna é conhecimento relacional de Deus, não apenas duração","A existência dos anjos","Uma existência após a ressurreição apenas"],correctIndex:1,explanation:"João 17:3: a vida eterna definida por Jesus como 'conhecer' (ginōskō — conhecimento relacional íntimo, não apenas intelectual) o Pai e o Filho. Começa agora, não apenas depois da morte.",reference:"João 17:3",category:.geral,propheticMeaning:"'Conhecer' a Deus (ginōskō) é a linguagem da aliança — o mesmo verbo de Adão 'conhecendo' Eva. A vida eterna não é sobrevivência mas intimidade: a comunhão para qual a humanidade foi criada, restaurada em Cristo, consumada na nova criação."),
]
